    if not signing_key:
        raise RuntimeError("MESSAGE_SIGNING_KEY environment variable is not set")

    envelope = json.loads(message_body.decode("utf-8"))
    signature = envelope.get("signature", "")
    payload_str = envelope.get("payload", "")

    expected_sig = hmac.new(
        signing_key.encode("utf-8"),
        payload_str.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    if not hmac.compare_digest(signature, expected_sig):
        raise ValueError("Message signature verification failed - rejecting message")

    return json.loads(payload_str)


